20: 
21: import org.apache.flink.annotation.PublicEvolving;
22: import org.apache.flink.annotation.VisibleForTesting;
23: import org.apache.flink.api.common.functions.ReduceFunction;
24: import org.apache.flink.api.common.state.ReducingState;
25: import org.apache.flink.api.common.state.ReducingStateDescriptor;
26: import org.apache.flink.api.common.typeutils.base.LongSerializer;
27: import org.apache.flink.streaming.api.windowing.windows.Window;
