package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

/**
 * A {@link WindowAssigner} that windows elements into sessions based on trading market hours.
 * Elements are assigned to time windows that correspond to trading sessions for a specific market,
 * such as NYSE (09:30-16:00 ET) or LSE (08:00-16:30 GMT).
 *
 * <p>Windows cannot overlap and are defined by market session boundaries rather than fixed time
 * intervals.
 *
 * <p>Example usage:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * KeyedStream<TradeEvent, String> keyed = trades.keyBy(t -> t.getSymbol());
 * WindowedStream<TradeEvent, String, TimeWindow> windowed =
 *   keyed.window(PricingSessionWindow.forMarket("NYSE", ZoneId.of("America/New_York"),
 *                                                LocalTime.of(9, 30), LocalTime.of(16, 0)));
 * }</pre>
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;
    private final boolean handleOvernightSessions;

    protected PricingSessionWindow(
            String marketId,
            ZoneId timezone,
            LocalTime sessionOpen,
            LocalTime sessionClose,
            boolean handleOvernightSessions) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("marketId cannot be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("timezone cannot be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException(
                    "sessionOpen and sessionClose times cannot be null");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
        this.handleOvernightSessions = handleOvernightSessions;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert timestamp to local date/time in the market's timezone
        Instant instant = Instant.ofEpochMilli(timestamp);
        ZonedDateTime zonedDateTime = instant.atZone(timezone);

        // Get the session start and end times for this date
        ZonedDateTime sessionStartTime =
                zonedDateTime.toLocalDate().atTime(sessionOpen).atZone(timezone);
        ZonedDateTime sessionEndTime =
                zonedDateTime.toLocalDate().atTime(sessionClose).atZone(timezone);

        // Handle overnight sessions (e.g., futures markets)
        if (handleOvernightSessions && zonedDateTime.toLocalTime().isBefore(sessionOpen)) {
            // This event is after midnight but before session open, so it belongs to previous day's
            // session
            sessionStartTime = sessionStartTime.minusDays(1);
            sessionEndTime = sessionEndTime.minusDays(1);
        }

        // Check if timestamp is within this session
        if (timestamp >= sessionStartTime.toInstant().toEpochMilli()
                && timestamp < sessionEndTime.toInstant().toEpochMilli()) {
            return Collections.singletonList(
                    new TimeWindow(
                            sessionStartTime.toInstant().toEpochMilli(),
                            sessionEndTime.toInstant().toEpochMilli()));
        }

        // If timestamp is outside session hours, find the next session start
        // For now, we assign to a window that starts at the next session open time
        ZonedDateTime nextSessionStart = sessionStartTime.plusDays(1);
        ZonedDateTime nextSessionEnd = sessionEndTime.plusDays(1);

        return Collections.singletonList(
                new TimeWindow(
                        nextSessionStart.toInstant().toEpochMilli(),
                        nextSessionEnd.toInstant().toEpochMilli()));
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public String toString() {
        return "PricingSessionWindow("
                + marketId
                + ", "
                + sessionOpen
                + "-"
                + sessionClose
                + " "
                + timezone
                + ")";
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    /** Merge overlapping {@link TimeWindow}s. */
    @Override
    public void mergeWindows(
            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    /**
     * Creates a new {@code PricingSessionWindow} for a specific market with defined session hours.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone in which the market operates
     * @param sessionOpen The local time when the market opens
     * @param sessionClose The local time when the market closes
     * @return A new PricingSessionWindow instance
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        return forMarket(marketId, timezone, sessionOpen, sessionClose, false);
    }

    /**
     * Creates a new {@code PricingSessionWindow} for a specific market with defined session hours.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone in which the market operates
     * @param sessionOpen The local time when the market opens
     * @param sessionClose The local time when the market closes
     * @param handleOvernightSessions If true, handles sessions that span across midnight (e.g.,
     *     futures markets)
     * @return A new PricingSessionWindow instance
     */
    public static PricingSessionWindow forMarket(
            String marketId,
            ZoneId timezone,
            LocalTime sessionOpen,
            LocalTime sessionClose,
            boolean handleOvernightSessions) {
        return new PricingSessionWindow(
                marketId, timezone, sessionOpen, sessionClose, handleOvernightSessions);
    }

    public String getMarketId() {
        return marketId;
    }

    public ZoneId getTimezone() {
        return timezone;
    }

    public LocalTime getSessionOpen() {
        return sessionOpen;
    }

    public LocalTime getSessionClose() {
        return sessionClose;
    }

    public boolean isHandleOvernightSessions() {
        return handleOvernightSessions;
    }
}

