package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} that fires when a pricing/trading session ends (at the window's end time).
 * This trigger is designed to work with {@link
 * org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow}.
 *
 * <p>The trigger fires at the market close (end of the trading session window) based on event
 * time. It supports optional early firing based on configurable events (e.g., circuit breaker
 * halts).
 *
 * <p>This trigger can be merged, which is required for use with merging window assigners.
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private PricingSessionTrigger() {}

    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Register the window end time as an event-time timer
        // This will fire when we reach the market close time
        ctx.registerEventTimeTimer(window.getEnd());

        // Continue processing, don't fire yet
        return TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Fire when the window end time is reached (market close)
        if (time == window.getEnd()) {
            return TriggerResult.FIRE;
        }
        return TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // We don't use processing time for trading sessions
        return TriggerResult.CONTINUE;
    }

    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        // Clean up the event-time timer registered for window end
        ctx.deleteEventTimeTimer(window.getEnd());
    }

    @Override
    public boolean canMerge() {
        return true;
    }

    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
        // When windows merge, re-register the timer for the new window's end time
        Long nextFireTime = window.getEnd();
        ctx.registerEventTimeTimer(nextFireTime);
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    /**
     * Creates a new instance of PricingSessionTrigger.
     *
     * @return A new PricingSessionTrigger instance
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }
}

